def test_visible_view_from_text_detects_streamlit_view_heading_fallback():
    text = "Roxy\n\nLive sin reload\n\nOpciones\nRoxy Trading\n\nScanner profesional"

    assert visible_view_from_text(text, "Opciones") == "Opciones"
    assert visible_view_from_text(text, "Dashboard") == ""


def test_dashboard_render_probe_classifies_browser_feature_warnings_as_soft():
    assert message_matches_any("Error: Unrecognized data set: source_0", SOFT_CONSOLE_ERROR_PATTERNS)
    assert message_matches_any("Unrecognized feature: 'battery'.", SOFT_CONSOLE_WARNING_PATTERNS)
    assert message_matches_any(
        "An iframe which has both allow-scripts and allow-same-origin for its sandbox attribute can escape its sandboxing.",
        SOFT_CONSOLE_WARNING_PATTERNS,
    )
    assert message_matches_any(
        "The input spec uses Vega-Lite v5.20.1, but the current version of Vega-Lite is v6.3.1.",
        SOFT_CONSOLE_WARNING_PATTERNS,
    )
    assert message_matches_any(
        'WARN Infinite extent for field "ts": [Infinity, -Infinity]', SOFT_CONSOLE_WARNING_PATTERNS
    )
    assert message_matches_any(
        'WARN Dropping "fit-x" because spec has discrete width.', SOFT_CONSOLE_WARNING_PATTERNS
    )
    assert not message_matches_any("Warning: slow chart update", SOFT_CONSOLE_WARNING_PATTERNS)


def test_dashboard_render_probe_deduplicates_soft_warning_samples():
    assert unique_messages(
        [
            "Unrecognized feature: 'battery'.",
            " unrecognized feature: 'battery'. ",
            "The input spec uses Vega-Lite v5.20.1",
        ]
    ) == ["Unrecognized feature: 'battery'.", "The input spec uses Vega-Lite v5.20.1"]


def test_dashboard_render_probe_classifies_soft_warning_families():
    assert soft_console_warning_family("Unrecognized feature: 'battery'.") == "browser_feature_policy"
    assert soft_console_warning_family("The input spec uses Vega-Lite v5.20.1") == "vega_lite_version"
    assert soft_console_warning_family('WARN Dropping "fit-x" because spec has discrete width.') == "vega_fit_width"
    assert message_family_counts(
        [
            "Unrecognized feature: 'battery'.",
            "The input spec uses Vega-Lite v5.20.1",
            "Unrecognized feature: 'ambient-light-sensor'.",
            'WARN Dropping "fit-x" because spec has discrete width.',
        ]
    ) == {"browser_feature_policy": 2, "vega_lite_version": 1, "vega_fit_width": 1}
    assert message_family_samples(
        [
            "WARN Infinite extent for field ts: [Infinity, -Infinity]",
            "warn infinite extent for field ts: [Infinity, -Infinity]",
            "Unrecognized feature: 'battery'.",
        ]
    ) == {
        "empty_chart_extent": ["WARN Infinite extent for field ts: [Infinity, -Infinity]"],
        "browser_feature_policy": ["Unrecognized feature: 'battery'."],
    }


def test_dashboard_render_probe_classifies_soft_error_families():
    assert soft_console_error_family("Error: Unrecognized data set: source_0") == "vega_unrecognized_dataset"
    assert soft_console_error_family("Error: cancelled animation frame") == "other_soft_error"
    assert message_family_counts(
        [
            "Error: Unrecognized data set: source_0",
            "Error: Unrecognized data set: source_1",
        ],
        classifier=soft_console_error_family,
    ) == {"vega_unrecognized_dataset": 2}
    assert message_family_samples(
        [
            "Error: Unrecognized data set: source_0",
            "error: unrecognized data set: source_0",
        ],
        classifier=soft_console_error_family,
    ) == {"vega_unrecognized_dataset": ["Error: Unrecognized data set: source_0"]}


def test_dashboard_render_probe_builds_page_error_detail_with_stack_context():
    class SyntheticPageError:
        name = "Error"
        message = "Unrecognized data set: source_0"
        stack = "Error: Unrecognized data set: source_0\n    at parse (vega-runtime.js:10:5)"

    detail = page_error_detail(
        SyntheticPageError(),
        url="http://127.0.0.1:3000/?view=Dashboard",
        phase="live_pulse_wait",
        elapsed_seconds=2.34567,
    )

    assert detail["text"] == "Error: Unrecognized data set: source_0"
    assert detail["family"] == "vega_unrecognized_dataset"
    assert detail["soft"] is True
    assert detail["phase"] == "live_pulse_wait"
    assert detail["elapsed_seconds"] == 2.346
    assert detail["url"] == "http://127.0.0.1:3000/?view=Dashboard"
    assert detail["stack_top_frame"] == "at parse (vega-runtime.js:10:5)"
    assert "vega-runtime.js:10:5" in str(detail["stack"])


def test_dashboard_render_probe_compacts_stack_without_collapsing_frames():
    stack = "Error: boom\n\n    at first (chart.js:1:2)\n" + ("x" * 1500)

    compacted = compact_frontend_stack(stack, max_length=80)

    assert "at first (chart.js:1:2)" in compacted
    assert "\n" in compacted
    assert len(compacted) <= 80


def test_dashboard_render_probe_summarizes_detail_values():
    details = [
        {"phase": "live_pulse_wait", "stack_top_frame": "at a"},
        {"phase": "live_pulse_wait", "stack_top_frame": "at b"},
        {"phase": "state_capture", "stack_top_frame": "at a"},
        {"phase": ""},
    ]

    assert detail_value_counts(details, "phase") == {"live_pulse_wait": 2, "state_capture": 1}
    assert frontend_stack_top_frame("Error: boom\n    at source (bundle.js:1:2)") == "at source (bundle.js:1:2)"


def _touch(path, now):
    ts = now.timestamp()
    os.utime(path, (ts, ts))


