def command_state_from_query_params(params, default_symbol="AAPL"):
    tf = params.get("tf", "1h")
    view = params.get("view", "Centro")
    return {"symbol": "AAPL", "market": "stock", "timeframe": tf, "page": view}

def sync_dashboard_query_params(params, *, symbol, market, timeframe, page):
    params["symbol"] = symbol
    params["market"] = market
    params["tf"] = timeframe
    params["view"] = page
    return True

def hydrate_focused_page_state(params, session_state, default_symbol="AAPL"):
    query_page = command_state_from_query_params(params, default_symbol)["page"]
    session_page = session_state.get("roxy_focused_page", "")
    page = session_page or query_page
    if session_page == "Dashboard" and query_page != "Dashboard":
        page = query_page
    session_state["roxy_last_selected_page"] = page
    return page

def current_focused_page_state(params, session_state, default_symbol="AAPL"):
    query_page = command_state_from_query_params(params, default_symbol)["page"]
    page = session_state.get("roxy_focused_page", "") or session_state.get("roxy_last_selected_page", "") or query_page
    if page == "Dashboard" and query_page != "Dashboard":
        page = query_page
    return page

