def test_validate_dashboard_history_hygiene_warns_when_history_is_stale_or_future(tmp_path):
    scan_db = tmp_path / "scan_history.csv"
    base = {
        "market": "stocks",
        "symbol": "AAPL",
        "tf": "1h",
        "signal": "WAIT",
        "score": 0,
    }
    pd.DataFrame([{**base, "ts": "2026-06-10T13:00:00+00:00"}]).to_csv(scan_db, index=False)

    stale = validate_dashboard_history_hygiene(
        scan_db,
        max_age_minutes=60,
        now=datetime(2026, 6, 10, 15, 0, tzinfo=timezone.utc),
    )
    assert stale["status"] == "WARN"
    assert stale["latest_age_minutes"] == 120.0
    assert "latest stale>60m" in stale["detail"]

    pd.DataFrame([{**base, "ts": "2026-06-10T15:10:00+00:00"}]).to_csv(scan_db, index=False)
    future = validate_dashboard_history_hygiene(scan_db, now=datetime(2026, 6, 10, 15, 0, tzinfo=timezone.utc))

    assert future["status"] == "WARN"
    assert future["latest_future_minutes"] == 10.0
    assert "latest future>10.0m" in future["detail"]


