def test_dashboard_history_needs_recovery_when_latest_ok_but_near_stale():
    default_near_stale = {
        "checks": [
            {
                "name": "dashboard_history_hygiene",
                "status": "OK",
                "exists": True,
                "latest_age_minutes": 37.0,
            }
        ]
    }
    default_still_fresh = {
        "checks": [
            {
                "name": "dashboard_history_hygiene",
                "status": "OK",
                "exists": True,
                "latest_age_minutes": 35.9,
            }
        ]
    }
    near_stale = {
        "checks": [
            {
                "name": "dashboard_history_hygiene",
                "status": "OK",
                "exists": True,
                "latest_age_minutes": 49.0,
            }
        ]
    }
    still_fresh = {
        "checks": [
            {
                "name": "dashboard_history_hygiene",
                "status": "OK",
                "exists": True,
                "latest_age_minutes": 47.5,
            }
        ]
    }

    assert dashboard_history_needs_recovery(default_near_stale) is True
    assert dashboard_history_needs_recovery(default_still_fresh) is False
    assert dashboard_history_needs_recovery(near_stale, max_ok_age_minutes=60.0) is True
    assert dashboard_history_needs_recovery(still_fresh, max_ok_age_minutes=60.0) is False


def test_dashboard_history_autoheal_enabled_for_explicit_or_report_generators():
    report_with_history = {
        "checks": [
            {
                "name": "dashboard_history_hygiene",
                "status": "OK",
                "exists": True,
                "latest_age_minutes": 55.0,
            }
        ]
    }
    report_without_history = {"checks": [{"name": "heartbeat", "status": "OK"}]}

    base_args = {
        "ensure_dashboard_history_sample": False,
        "ensure_alert_quality_report": False,
        "ensure_status_snapshot_report": False,
        "ensure_daily_opportunity_plan_report": False,
    }

    assert dashboard_history_autoheal_enabled(
        argparse.Namespace(**{**base_args, "ensure_dashboard_history_sample": True}),
        report_without_history,
    )
    assert dashboard_history_autoheal_enabled(
        argparse.Namespace(**{**base_args, "ensure_alert_quality_report": True}),
        report_with_history,
    )
    assert dashboard_history_autoheal_enabled(
        argparse.Namespace(**{**base_args, "ensure_status_snapshot_report": True}),
        report_with_history,
    )
    assert dashboard_history_autoheal_enabled(
        argparse.Namespace(**{**base_args, "ensure_daily_opportunity_plan_report": True}),
        report_with_history,
    )
    assert not dashboard_history_autoheal_enabled(argparse.Namespace(**base_args), report_with_history)
    assert not dashboard_history_autoheal_enabled(
        argparse.Namespace(**{**base_args, "ensure_alert_quality_report": True}),
        report_without_history,
    )


def test_dashboard_render_probe_autoheal_enabled_does_not_require_app_url():
    report = {
        "checks": [
            {"name": "dashboard_render_probe", "status": "OK", "age_minutes": 3.0},
            {"name": "dashboard_search_render_probe", "status": "OK", "age_minutes": 3.0},
        ]
    }

    assert dashboard_render_probe_autoheal_enabled(
        argparse.Namespace(
            ensure_dashboard_render_probe_report=True,
            dashboard_probe_refresh_minutes=0.0,
            app_url="",
        ),
        report,
    )
    assert not dashboard_render_probe_autoheal_enabled(
        argparse.Namespace(
            ensure_dashboard_render_probe_report=False,
            dashboard_probe_refresh_minutes=0.0,
            app_url="",
        ),
        report,
    )


