def test_validate_app_url_retries_once_after_timeout(tmp_path, monkeypatch):
    now = datetime(2026, 6, 10, 12, 0, tzinfo=timezone.utc)
    log_path = tmp_path / "streamlit_launchd.err"
    log_path.write_text("2026-06-10 12:00:00 app heartbeat ok\n")
    _touch(log_path, now)

    class Response:
        status = 200

        def __enter__(self):
            return self

        def __exit__(self, exc_type, exc, tb):
            return False

    calls = {"count": 0}

    def fake_urlopen(*args, **kwargs):
        calls["count"] += 1
        if calls["count"] <= 2:
            raise TimeoutError("timed out")
        return Response()

    monkeypatch.setattr(roxy_realtime_check, "urlopen", fake_urlopen)
    monkeypatch.setattr(roxy_realtime_check.time, "sleep", lambda _seconds: None)

    status = validate_app_url(
        "http://127.0.0.1:3000",
        timeout=0.1,
        timeout_retry_seconds=0.2,
        log_paths=[log_path],
        now=now,
    )

    assert status["status"] == "OK"
    assert status["probe_attempts"] == 2
    assert status["retried_after_timeout"] is True
    assert calls["count"] == 3


def test_evaluate_realtime_health_passes_with_good_artifacts(tmp_path, monkeypatch):
    class PsResult:
        returncode = 0
        stdout = "101 /usr/bin/python /Users/robertograu/roxy_trading/tools/ma_live.py --market both\n"
        stderr = ""

    original_run = roxy_realtime_check.subprocess.run

    def fake_run(cmd, *args, **kwargs):
        if cmd == ["ps", "axo", "pid=,command="]:
            return PsResult()
        return original_run(cmd, *args, **kwargs)

    monkeypatch.setattr(roxy_realtime_check.subprocess, "run", fake_run)
    now = datetime(2026, 6, 8, 12, 0, tzinfo=timezone.utc)
    _write_good_artifacts(tmp_path, now - timedelta(minutes=2))

    report = evaluate_realtime_health(base_dir=tmp_path, now=now, skip_chart_fetch=True, skip_service_check=True)

    assert report["status"] == "WARN"
