def test_refresh_report_metrics_contract_replaces_stale_check():
    report = {
        "status": "WARN",
        "ok": False,
        "checks": [
            {"name": "report_metrics_contract", "status": "WARN", "detail": "stale"},
            {
                "name": "chart_realtime_health_report",
                "status": "OK",
                "detail": "charts",
                "malformed": False,
                "age_minutes": 1.2,
                "checked_count": 4,
                "operable_checked_count": 2,
                "fail_count": 0,
                "warn_count": 0,
                "operable_min_freshness_margin_minutes": 25.0,
                "operable_freshness_margin_state": "OK",
                "required_chart_symbols": ["BTC/USD"],
                "covered_chart_symbols": ["BTC/USD", "ETH/USD"],
                "missing_required_chart_symbol_count": 0,
            },
        ],
    }

    refresh_report_metrics_contract(report)

    contract_checks = [item for item in report["checks"] if item["name"] == "report_metrics_contract"]
    assert len(contract_checks) == 1
    assert contract_checks[0]["status"] == "OK"
    assert contract_checks[0]["metrics_key_count"] >= 4
    assert report["metrics"]["chart_realtime_health_status"] == "OK"
    assert report["metrics"]["chart_realtime_health_healthy"] is True
    assert report["metrics"]["chart_health_age_minutes"] == 1.2
    assert report["metrics"]["chart_health_required_symbols"] == ["BTC/USD"]
    assert report["metrics"]["chart_health_covered_symbols"] == ["BTC/USD", "ETH/USD"]
    assert report["status"] == "OK"
    assert report["ok"] is True


