def test_build_operational_summary_prioritizes_system_failures():
    summary = build_operational_summary(
        {
            "status": "FAIL",
            "checks": [{"name": "streamlit_app", "status": "FAIL", "detail": "HTTP timeout"}],
        },
        alert_quality_report={"summary": {"state": "READY", "latest_notifications_ready": 2}},
    )

    assert summary["mode"] == "SYSTEM_FAIL"
    assert summary["label"] == "Sistema falla"
    assert summary["tone"] == "avoid"
    assert "streamlit_app" in summary["detail"]


def test_build_operational_summary_preserves_safe_route_during_system_fail():
    report = {
        "status": "FAIL",
        "checks": [
            {"name": "runtime_backup_report", "status": "FAIL", "detail": "archive not verified"},
            {
                "name": "alpaca_account_probe",
                "status": "WARN",
                "auth_ok": False,
                "diagnosis": "alpaca_account_auth_failed",
                "error_category": "AUTH_INVALID",
            },
            {
                "name": "status_snapshot",
                "status": "OK",
                "safe_mode": "NO_STOCK_OR_OPTIONS_ALERTS",
                "confirmation_gate": "NO_TRADE_FROM_FALLBACK",
                "allowed_markets": ["crypto"],
                "blocked_markets": ["stock", "options"],
                "active_route": "PARTIAL_MARKET_ROUTE",
                "active_route_label": "Operar solo CRYPTO",
                "active_route_detail": "Operable CRYPTO; bloqueado STOCK, OPTIONS.",
            },
        ],
        "market_realtime": {
            "allowed_markets": ["crypto"],
            "blocked_markets": ["stock", "options"],
            "active_route": "PARTIAL_MARKET_ROUTE",
            "active_route_label": "Operar solo CRYPTO",
            "active_route_detail": "Operable CRYPTO; bloqueado STOCK, OPTIONS.",
        },
        "provider_recovery": {
            "label": "Premium bloqueado",
            "premium_blocked": True,
            "stock_alerts_allowed": False,
            "safe_mode": "NO_STOCK_OR_OPTIONS_ALERTS",
            "confirmation_gate": "NO_TRADE_FROM_FALLBACK",
        },
    }

    summary = build_operational_summary(
        report,
        alert_quality_report={
            "summary": {
                "state": "BLOCKED_REALTIME",
                "latest_notifications_ready": 0,
                "latest_total_opportunities": 3,
                "blocker_category": "MARKET_PARTIAL_BLOCK",
            }
        },
    )
    report["operational_summary"] = summary

    assert summary["mode"] == "SYSTEM_FAIL"
    assert summary["label"] == "Sistema falla"
    assert summary["active_route_label"] == "Operar solo CRYPTO"
    assert summary["safe_mode"] == "NO_STOCK_OR_OPTIONS_ALERTS"
    assert summary["confirmation_gate"] == "NO_TRADE_FROM_FALLBACK"
    assert summary["allowed_markets"] == ["crypto"]
    assert summary["blocked_markets"] == ["stock", "options"]
    assert summary["stock_alerts_allowed"] is False
    assert summary["crypto_alerts_allowed"] is True
    assert summary["options_alerts_allowed"] is False
    assert validate_operational_summary_contract(report)["status"] == "OK"
    assert validate_provider_recovery_contract(report)["status"] == "OK"


def test_build_operational_summary_distinguishes_market_waiting_from_system_failure():
    summary = build_operational_summary(
        {"status": "OK", "checks": [{"name": "heartbeat", "status": "OK", "detail": "ok"}]},
        alert_quality_report={
            "summary": {
                "state": "WAITING",
                "latest_notifications_ready": 0,
                "latest_total_opportunities": 8,
                "diagnostic_label": "Bloqueador x22",
                "diagnostic_detail": "15m da entrada: WAIT",
                "latest_top_blocker_streak": 22,
            }
        },
    )

    assert summary["mode"] == "MARKET_WAITING"
    assert summary["label"] == "Mercado espera"
    assert summary["tone"] == "watch"
    assert "Bloqueador x22" in summary["detail"]


def test_build_operational_summary_surfaces_premium_block_as_data_issue():
    summary = build_operational_summary(
        {
            "status": "WARN",
            "checks": [{"name": "chart_provider_effective", "status": "WARN", "detail": "alpaca_auth"}],
            "market_realtime": {
                "allowed_markets": ["crypto"],
                "blocked_markets": ["stock", "options"],
                "active_route": "PARTIAL_MARKET_ROUTE",
                "active_route_label": "Operar solo CRYPTO",
                "active_route_detail": "Operable CRYPTO; bloqueado STOCK, OPTIONS.",
            },
            "provider_recovery": {
                "label": "Premium bloqueado",
                "detail": "3/4 acciones caen a fallback por auth/permisos.",
                "action": "Configurar POLYGON_API_KEY/POLYGON_API_TOKEN.",
                "premium_blocked": True,
                "stock_alerts_allowed": False,
                "impacted_markets": ["stock", "options"],
                "safe_mode": "NO_STOCK_OR_OPTIONS_ALERTS",
                "confirmation_gate": "NO_TRADE_FROM_FALLBACK",
            },
        },
        alert_quality_report={
            "summary": {
                "state": "BLOCKED_REALTIME",
                "latest_notifications_ready": 0,
                "latest_total_opportunities": 3,
                "diagnostic_detail": "Datos realtime: Premium bloqueado",
            }
        },
    )

    assert summary["mode"] == "PREMIUM_BLOCKED"
    assert summary["label"] == "Premium bloqueado"
    assert summary["tone"] == "avoid"
