def test_append_health_history_trims_to_max_entries(tmp_path):
    history_path = tmp_path / "history.jsonl"

    for idx in range(5):
        append_health_history(
            {"status": "OK", "generated_at": f"2026-06-08T12:0{idx}:00+00:00", "checks": []},
            history_path=history_path,
            max_entries=3,
        )

    lines = history_path.read_text().splitlines()
    payloads = [json.loads(line) for line in lines]
    assert len(lines) == 3
    assert payloads[0]["generated_at"] == "2026-06-08T12:02:00+00:00"
    assert payloads[-1]["generated_at"] == "2026-06-08T12:04:00+00:00"


def test_health_history_writes_compact_jsonl(tmp_path):
    history_path = tmp_path / "history.jsonl"
    history_path.write_text(
        json.dumps({"generated_at": "2026-06-08T11:59:00+00:00", "metrics": {"disk_free_gb": 90.0}}) + "\n"
    )
    report = {
        "status": "OK",
        "generated_at": "2026-06-08T12:00:00+00:00",
        "checks": [{"name": "heartbeat", "status": "OK", "detail": "fresh"}],
    }

    append_health_history(report, history_path=history_path, max_entries=3)
    lines = history_path.read_text().splitlines()
    assert len(lines) == 2
    assert all('": ' not in item for item in lines)
    line = lines[-1]

    assert '":' in line
    assert '": ' not in line
    assert '", "' not in line

    entry = json.loads(line)
    entry["metrics"]["disk_free_gb"] = 88.5
    assert roxy_realtime_check.replace_latest_health_history_entry(history_path, entry)
    rewritten = history_path.read_text().splitlines()[-1]
    assert '": ' not in rewritten
    assert json.loads(rewritten)["metrics"]["disk_free_gb"] == 88.5


def test_health_history_storage_excludes_recursive_slo_metrics(tmp_path):
    history_path = tmp_path / "history.jsonl"
    report = {
        "status": "WARN",
        "generated_at": "2026-06-10T12:00:00+00:00",
        "checks": [
            {
                "name": "notification_delivery",
                "status": "OK",
                "detail": "history ok",
                "history_line_count": 120,
                "history_max_lines": 500,
                "history_size_bytes": 42_000,
                "history_max_bytes": 1_000_000,
            },
            {
                "name": "health_stability_slo",
                "status": "INFO",
                "detail": "derived",
                "ok_rate": 0.9,
                "core_ok_rate": 1.0,
                "latest_notification_history_line_count": 120,
                "latest_report_metrics_contract_metrics_key_count": 1300,
            },
        ],
    }

    full_entry = health_history_entry(report)
    assert full_entry["metrics"]["health_stability_slo_ok_rate"] == 0.9
    assert full_entry["metrics"]["health_stability_slo_latest_notification_history_line_count"] == 120

    append_health_history(report, history_path=history_path)
    stored = json.loads(history_path.read_text().splitlines()[-1])

    assert stored["storage_compacted"] is True
    assert stored["storage_removed_metric_count"] >= 4
    assert stored["storage_excluded_metric_prefixes"] == ["health_stability_slo_"]
    assert "health_stability_slo_ok_rate" not in stored["metrics"]
    assert "health_stability_slo_latest_notification_history_line_count" not in stored["metrics"]
    assert stored["metrics"]["notification_history_line_count"] == 120
    assert stored["checks"]["health_stability_slo"] == "INFO"


def test_health_history_storage_compacts_duplicate_metric_aliases():
    entry = {
        "status": "WARN",
        "generated_at": "2026-06-10T12:00:00+00:00",
        "checks": {"alert_quality_report": "WARN", "status_snapshot": "WARN"},
        "metrics": {
            "alert_quality_state": "BLOCKED_REALTIME",
            "status_snapshot_alert_quality_state": "BLOCKED_REALTIME",
            "alert_quality_false_negative_risk": "HIGH",
            "status_snapshot_alert_quality_false_negative_risk": "MEDIUM",
            "status_snapshot_alert_quality_issue_count": 1,
            "alert_quality_recommended_action": "Rotacion confirmada",
            "alert_quality_action": "Rotacion confirmada",
            "alert_quality_operational_focus_reason": "Rotacion confirmada",
            "status_snapshot_recommended_action": "Rotacion confirmada",
            "status_snapshot_operational_focus_reason": "Rotacion confirmada",
            "alert_quality_missed_trigger_plan_decision_action": "Escalar rotacion",
            "alert_quality_missed_trigger_plan_review_action": "Escalar rotacion",
            "health_stability_slo_ok_rate": 0.8,
        },
    }

    stored = roxy_realtime_check.compact_health_history_storage_entry(entry)

    assert stored["storage_compacted"] is True
    assert stored["storage_removed_metric_count"] == 7
    assert stored["storage_removed_duplicate_metric_alias_count"] == 1
    assert stored["storage_removed_duplicate_metric_key_alias_count"] == 5
    assert stored["storage_duplicate_metric_prefix_aliases"] == ["status_snapshot_alert_quality_->alert_quality_"]
    assert stored["storage_duplicate_metric_key_alias_sample"] == [
        "alert_quality_action->alert_quality_recommended_action",
        "alert_quality_operational_focus_reason->alert_quality_recommended_action",
        "status_snapshot_recommended_action->alert_quality_recommended_action",
        "status_snapshot_operational_focus_reason->alert_quality_recommended_action",
    ]
    assert (
        stored["storage_duplicate_metric_key_alias_sample_limit"]
        == roxy_realtime_check.HEALTH_HISTORY_STORAGE_DUPLICATE_ALIAS_SAMPLE_LIMIT
    )
    assert stored["metrics"]["alert_quality_state"] == "BLOCKED_REALTIME"
    assert "status_snapshot_alert_quality_state" not in stored["metrics"]
    assert stored["metrics"]["status_snapshot_alert_quality_false_negative_risk"] == "MEDIUM"
    assert stored["metrics"]["status_snapshot_alert_quality_issue_count"] == 1
    assert stored["metrics"]["alert_quality_recommended_action"] == "Rotacion confirmada"
    assert "alert_quality_action" not in stored["metrics"]
    assert "alert_quality_operational_focus_reason" not in stored["metrics"]
    assert "status_snapshot_recommended_action" not in stored["metrics"]
    assert "status_snapshot_operational_focus_reason" not in stored["metrics"]
    assert stored["metrics"]["alert_quality_missed_trigger_plan_decision_action"] == "Escalar rotacion"
    assert "alert_quality_missed_trigger_plan_review_action" not in stored["metrics"]
    assert "health_stability_slo_ok_rate" not in stored["metrics"]


