def test_ensure_post_append_health_history_maintenance_waits_until_trigger(tmp_path):
    history_path = tmp_path / "history.jsonl"
    now = datetime.now(timezone.utc)
    rows = [
        {
            "status": "OK",
            "generated_at": (now - timedelta(minutes=200 - idx)).isoformat(),
            "pad": "x" * 220,
        }
        for idx in range(200)
    ]
    history_path.write_text("\n".join(json.dumps(row) for row in rows) + "\n")
    target_window_ratio = DEFAULT_HEALTH_HISTORY_MAINTENANCE_TRIGGER_RATIO - 0.039
    max_bytes = int(history_path.stat().st_size / target_window_ratio)
    before = validate_health_history_integrity(history_path, max_entries=200, max_bytes=max_bytes)

    result = ensure_post_append_health_history_maintenance(
        history_path=history_path,
        max_entries=200,
        max_bytes=max_bytes,
        min_entries=5,
    )
    after = validate_health_history_integrity(history_path, max_entries=200, max_bytes=max_bytes)

    assert DEFAULT_HEALTH_HISTORY_MAINTENANCE_TARGET_RATIO < before["budget_ratio"]
    assert before["budget_ratio"] < DEFAULT_HEALTH_HISTORY_MAINTENANCE_TRIGGER_RATIO
    assert before["maintenance_due"] is False
    assert before["maintenance_preemptive_due"] is False
    assert before["maintenance_plan_state"] == "WATCH"
    assert before["maintenance_plan_action"] == "monitor"
    assert result["action"] == "skipped_not_due"
    assert result["ok"] is True
    assert result["configured_min_entries"] == 5
    assert result["effective_min_entries"] == 5
    assert result["min_entry_floor"] == 2
    assert result["target_fit_entries"] >= result["configured_min_entries"]
    assert result["target_fit_entries"] <= len(rows)
    assert result["min_entries_relaxed"] is False
    assert result["before_maintenance_preemptive_due"] is False
    assert result["before_maintenance_plan_state"] == "WATCH"
    assert result["before_maintenance_plan_action"] == "monitor"
    assert result["maintenance_estimated_appends_until_trigger"] > 0
    assert result["after_status"] == before["status"]
    assert result["after_size_bytes"] == before["size_bytes"]
    assert result["after_budget_ratio"] == before["budget_ratio"]
    assert result["after_maintenance_due"] == before["maintenance_due"]
    assert result["after_line_count"] == before["line_count"]
    assert result["removed_lines"] == 0
    assert result["removed_bytes"] == 0
    assert after["line_count"] == len(rows)
    assert after["budget_ratio"] == before["budget_ratio"]


