def test_write_run_lock_status_records_blocked_and_released(tmp_path):
    now = datetime(2026, 6, 10, 12, 0, tzinfo=timezone.utc)
    status_path = tmp_path / "alerts" / "roxy_realtime_lock.json"
    lock_info = {
        "acquired": False,
        "lock_path": str(tmp_path / "roxy.lock"),
        "pid": 123,
        "started_at": (now - timedelta(minutes=4)).isoformat(),
        "age_minutes": 4.0,
        "stale_minutes": 30.0,
        "owner_command": "roxy_realtime_check.py --ensure-chart-health-report",
        "owner_command_flags": ["--ensure-chart-health-report"],
        "blocked_command": "roxy_realtime_check.py --ensure-dashboard-render-probe-report",
        "blocked_command_flags": ["--ensure-dashboard-render-probe-report"],
    }

    blocked = write_run_lock_status(lock_info, status_path, event="blocked", now=now)
    released = write_run_lock_status(
        {**lock_info, "acquired": True}, status_path, event="released", now=now + timedelta(minutes=1)
    )
    payload = json.loads(status_path.read_text())

    assert blocked["event"] == "blocked"
    assert blocked["acquired"] is False
    assert blocked["owner_command_flags"] == ["--ensure-chart-health-report"]
    assert blocked["blocked_command_flags"] == ["--ensure-dashboard-render-probe-report"]
    assert released["event"] == "released"
    assert released["acquired"] is False
    assert payload["event"] == "released"
    assert payload["acquired"] is False
    assert payload["released_at"] == (now + timedelta(minutes=1)).isoformat()


