def test_summarize_health_history_entries_reports_recent_lock_contention_separately():
    rows = []
    for idx in range(25):
        row = {"status": "OK", "generated_at": f"2026-06-08T12:{idx:02d}:00+00:00"}
        if idx in {2, 23}:
            row = {
                "status": "WARN",
                "generated_at": f"2026-06-08T12:{idx:02d}:00+00:00",
                "top_issue": {"name": "realtime_lock_status", "status": "WARN"},
                "checks": {"realtime_lock_status": "WARN"},
                "metrics": {"realtime_lock_event": "blocked", "realtime_lock_blocked_age_minutes": 0.2},
            }
        rows.append(row)

    summary = summarize_health_history_entries(rows, recent_lock_window=10)

    assert summary["status"] == "OK"
    assert summary["transient_lock_contention_count"] == 2
    assert summary["recent_transient_lock_contention_count"] == 1
    assert summary["transient_lock_contention_rate"] == 0.08
    assert summary["recent_transient_lock_contention_rate"] == 0.1
    assert summary["lock_contention_pressure"] == "LOW"
    assert summary["lock_contention_severity"] == "MICRO"
    assert summary["lock_contention_profile"] == "MICRO_CHURN"
    assert summary["transient_lock_contention_max_age_minutes"] == 0.2
    assert summary["recent_transient_lock_contention_max_age_minutes"] == 0.2
    assert summary["recent_transient_lock_contention_avg_age_minutes"] == 0.2
    assert summary["recent_lock_window"] == 10


