def test_validate_health_stability_slo_keeps_disk_attention_warn_after_provider_degrade(tmp_path):
    history = tmp_path / "history.jsonl"
    rows = [
        {
            "status": "WARN",
            "generated_at": f"2026-06-08T12:0{idx}:00+00:00",
            "top_issue": {"name": "alpaca_account_probe", "status": "WARN"},
            "checks": {"alpaca_account_probe": "WARN", "chart_provider_effective": "WARN"},
            "metrics": {
                "provider_recovery_premium_blocked": True,
                "provider_recovery_label": "Premium bloqueado",
                "provider_recovery_primary_provider_issue": "alpaca_auth",
                "provider_recovery_credential_diagnosis": "Corregir credenciales Alpaca.",
                "disk_free_gb": 108.0 - (idx * 12.0),
                "disk_free_pct": 48.0 - (idx * 5.8),
                "project_storage_gb": 1.5,
                "status_snapshot_alert_quality_sync_checked": True,
                "status_snapshot_alert_quality_issue_count": 0,
                "operational_summary_contract_checked": True,
                "operational_summary_contract_issue_count": 0,
                "provider_recovery_contract_checked": True,
                "provider_recovery_contract_issue_count": 0,
            },
        }
        for idx in range(5)
    ]
    history.write_text("\n".join(json.dumps(row) for row in rows) + "\n")

    status = validate_health_stability_slo(history, min_sample_size=5, warn_ok_rate=0.90, fail_ok_rate=0.75)

    assert status["status"] == "WARN"
    assert status["known_issue_degraded"] is True
    assert status["provider_block_isolated"] is True
    assert status["disk_free_drop_pressure"] == "ATTENTION"
    assert status["disk_free_drop_source"] == "OUTSIDE_PROJECT"
    assert "disk free drop attention 48.0GiB source outside_project free 24.8%" in status["issues"]
    assert "known Premium bloqueado degraded" in status["detail"]


