def test_validate_health_stability_slo_warns_when_ok_rate_slips(tmp_path):
    history = tmp_path / "history.jsonl"
    rows = [
        {"status": "OK", "generated_at": "2026-06-08T12:00:00+00:00"},
        {"status": "OK", "generated_at": "2026-06-08T12:01:00+00:00"},
        {"status": "OK", "generated_at": "2026-06-08T12:02:00+00:00"},
        {"status": "OK", "generated_at": "2026-06-08T12:03:00+00:00"},
        {"status": "WARN", "generated_at": "2026-06-08T12:04:00+00:00", "top_issue": {"name": "heartbeat"}},
    ]
    history.write_text("\n".join(json.dumps(row) for row in rows) + "\n")

    status = validate_health_stability_slo(history, min_sample_size=5, warn_ok_rate=0.90, fail_ok_rate=0.50)

    assert status["status"] == "WARN"
    assert status["ok_rate"] == 0.8
    assert status["warn_rate"] == 0.2
    assert status["fail_rate"] == 0.0
    assert status["core_warn_rate"] == 0.2
    assert status["core_fail_rate"] == 0.0
    assert status["dominant_issue"] == {"name": "heartbeat", "count": 1}


def test_validate_health_stability_slo_marks_dominant_issue_historical_recovered(tmp_path):
    history = tmp_path / "history.jsonl"
