def test_validate_health_stability_slo_warns_on_dashboard_probe_refresh_guard(tmp_path):
    history = tmp_path / "history.jsonl"

    def dashboard_metrics(age_minutes: float) -> dict[str, object]:
        metrics: dict[str, object] = {}
        for prefix, text_length in (
            ("dashboard_render", 14000),
            ("dashboard_search_render", 15000),
        ):
            metrics.update(
                {
                    f"{prefix}_check_status": "OK",
                    f"{prefix}_probe_status": "OK",
                    f"{prefix}_age_minutes": age_minutes,
                    f"{prefix}_max_age_minutes": 90.0,
                    f"{prefix}_text_length": text_length,
                    f"{prefix}_black_screen": False,
                    f"{prefix}_live_no_reload": True,
                    f"{prefix}_view_persisted": True,
                    f"{prefix}_selected_view_persisted": True,
                    f"{prefix}_symbol_persisted": True,
                    f"{prefix}_market_persisted": True,
                    f"{prefix}_timeframe_persisted": True,
                }
            )
        return metrics

    rows = [
        {
            "status": "OK",
            "generated_at": f"2026-06-08T12:0{idx}:00+00:00",
            "metrics": dashboard_metrics(30.0 + idx),
        }
        for idx in range(5)
    ]
    history.write_text("\n".join(json.dumps(row) for row in rows) + "\n")

    status = validate_health_stability_slo(history, min_sample_size=5, warn_ok_rate=0.90, fail_ok_rate=0.75)

    assert status["status"] == "WARN"
    assert status["latest_dashboard_probes_fresh"] is True
    assert status["latest_dashboard_probe_margin_state"] == "OK"
    assert status["latest_dashboard_probe_refresh_margin_state"] == "WATCH"
    assert status["latest_dashboard_probe_min_refresh_margin_minutes"] == 3.5
    assert "dashboard probe refresh guard watch 3.5m warn<=7.5m render" in status["issues"]
    assert "refresh_margin 3.5m watch refresh_warn<=7.5m" in status["detail"]


