def test_health_notification_incident_key_distinguishes_alert_quality_review_under_premium_block():
    base_report = {
        "status": "WARN",
        "operational_summary": {
            "mode": "PREMIUM_BLOCKED",
            "safe_mode": "NO_STOCK_OR_OPTIONS_ALERTS",
            "active_route": "PARTIAL_MARKET_ROUTE",
            "active_route_label": "Operar solo CRYPTO",
            "blocker_category": "MARKET_TRIGGER_WAIT",
            "detail": "Esperando gatillo 15m.",
        },
        "provider_recovery": {
            "primary_provider_issue": "alpaca_auth",
            "alpaca_account_error_category": "AUTH_INVALID",
        },
        "checks": [{"name": "alpaca_account_probe", "status": "WARN", "detail": "AUTH_INVALID"}],
    }
    quality_report = {
        **base_report,
        "checks": [
            {
                "name": "alert_quality_report",
                "status": "WARN",
                "detail": "review overdue",
                "missed_trigger_plan_review_pressure": "OVERDUE",
                "missed_trigger_plan_auto_review_decision": "REVALIDATE_NOW",
                "false_negative_risk": "HIGH",
                "top_symbol": "BTC/USD",
            },
            {"name": "alpaca_account_probe", "status": "WARN", "detail": "AUTH_INVALID"},
        ],
    }

    base_key = health_notification_incident_key(base_report, health_notification_message(base_report))
    quality_key = health_notification_incident_key(quality_report, health_notification_message(quality_report))

    assert base_key != quality_key
    assert "ALERT_QUALITY_REVIEW" not in base_key
    assert quality_key.endswith("ALERT_QUALITY_REVIEW|OVERDUE|REVALIDATE_NOW|HIGH|BTC/USD")


def test_health_notification_incident_key_uses_confirmed_alert_quality_handoff_context():
    base_report = {
        "status": "WARN",
        "operational_summary": {
            "mode": "PREMIUM_BLOCKED",
            "safe_mode": "NO_STOCK_OR_OPTIONS_ALERTS",
            "active_route": "PARTIAL_MARKET_ROUTE",
            "blocker_category": "MARKET_TRIGGER_WAIT",
            "detail": "Esperando gatillo 15m x17.",
        },
        "provider_recovery": {
            "primary_provider_issue": "alpaca_auth",
            "alpaca_account_error_category": "AUTH_INVALID",
        },
        "checks": [
            {
                "name": "alert_quality_report",
                "status": "WARN",
                "detail": "review overdue +19 cycles",
                "missed_trigger_plan_review_pressure": "OVERDUE_ESCALATED",
                "missed_trigger_plan_auto_review_decision": "ESCALATE_ROTATION",
                "missed_trigger_plan_review_overdue_cycles": 19,
                "missed_trigger_plan_rotation_next_symbol": "BTC/USD",
                "missed_trigger_plan_rotation_handoff_status": "CONFIRMED",
                "missed_trigger_plan_rotation_handoff_symbol": "BTC/USD",
                "missed_trigger_plan_rotation_handoff_source": "ALERT_QUALITY_ROTATION",
                "false_negative_risk": "HIGH",
                "operational_focus_symbol": "BTC/USD",
                "top_symbol": "ETH/USD",
            },
            {"name": "alpaca_account_probe", "status": "WARN", "detail": "AUTH_INVALID"},
        ],
    }
    volatile_report = {
        **base_report,
        "operational_summary": {
            **base_report["operational_summary"],
            "detail": "Esperando gatillo 15m x18.",
        },
        "checks": [
            {
                **base_report["checks"][0],
                "detail": "review overdue +20 cycles",
                "missed_trigger_plan_review_overdue_cycles": 20,
                "missed_trigger_plan_decision_action": "Escalar rotacion con nuevo texto operativo.",
            },
            base_report["checks"][1],
        ],
    }
    unconfirmed_report = {
        **base_report,
        "checks": [
            {
                **base_report["checks"][0],
                "missed_trigger_plan_rotation_handoff_status": "",
                "missed_trigger_plan_rotation_handoff_symbol": "",
                "missed_trigger_plan_rotation_handoff_source": "",
            },
            base_report["checks"][1],
        ],
    }

    confirmed_key = health_notification_incident_key(base_report, health_notification_message(base_report))
    volatile_key = health_notification_incident_key(volatile_report, health_notification_message(volatile_report))
    unconfirmed_key = health_notification_incident_key(
        unconfirmed_report, health_notification_message(unconfirmed_report)
    )

    assert confirmed_key == volatile_key
    assert confirmed_key.endswith(
        "ALERT_QUALITY_REVIEW|OVERDUE_ESCALATED|ESCALATE_ROTATION|HIGH|CONFIRMED|BTC/USD|ALERT_QUALITY_ROTATION"
    )
    assert unconfirmed_key.endswith("ALERT_QUALITY_REVIEW|OVERDUE_ESCALATED|ESCALATE_ROTATION|HIGH|BTC/USD")
    assert unconfirmed_key != confirmed_key


