def test_notify_health_if_needed_uses_dedicated_state_and_cooldown(tmp_path, monkeypatch):
    calls = []
    now = datetime(2026, 6, 8, 12, 0, tzinfo=timezone.utc)
    report = {
        "status": "FAIL",
        "checks": [{"name": "heartbeat", "status": "FAIL", "detail": "network unavailable"}],
    }

    def fake_send(message, *, reason, header, metadata=None):
        calls.append({"message": message, "reason": reason, "header": header, "metadata": metadata})
        return {"sent": True, "reason": reason, "message": message, **(metadata or {})}

    monkeypatch.setattr("notifier.send_notification_message", fake_send)
    state_path = tmp_path / "health_state.json"

    first = notify_health_if_needed(report, state_path=state_path, cooldown_minutes=30, now=now)
    second = notify_health_if_needed(report, state_path=state_path, cooldown_minutes=30, now=now + timedelta(minutes=5))

    assert first["sent"] is True
    assert second["sent"] is False
    assert second["reason"] == "cooldown"
    assert calls == [
        {
            "message": "ROXY HEALTH FAIL | heartbeat: network unavailable",
            "reason": "health_watchdog",
            "header": "ROXY HEALTH",
            "metadata": {"incident_key": "FAIL|heartbeat|FAIL"},
        }
    ]


def test_notify_health_if_needed_sends_recovery_after_failure(tmp_path, monkeypatch):
    calls = []
    now = datetime(2026, 6, 8, 12, 0, tzinfo=timezone.utc)
    state_path = tmp_path / "health_state.json"
    state_path.write_text(json.dumps({"last_status": "FAIL", "last_message": "ROXY HEALTH FAIL | heartbeat: failed"}))

    def fake_send(message, *, reason, header, metadata=None):
        calls.append(message)
        return {"sent": True, "reason": reason, "message": message, **(metadata or {})}

    monkeypatch.setattr("notifier.send_notification_message", fake_send)

    result = notify_health_if_needed(
        {
            "status": "OK",
            "operational_summary": {"label": "Mercado espera", "detail": "Esperando gatillo"},
            "checks": [],
        },
        state_path=state_path,
        now=now,
    )

    assert result["sent"] is True
    assert calls == ["ROXY HEALTH OK | recovered | Mercado espera: Esperando gatillo"]


def test_notify_health_if_needed_cools_down_recorded_local_attempts(tmp_path, monkeypatch):
    calls = []
    now = datetime(2026, 6, 8, 12, 0, tzinfo=timezone.utc)
    report = {
        "status": "WARN",
        "checks": [{"name": "notification_delivery", "status": "INFO", "detail": "local only"}],
    }

    def fake_send(message, *, reason, header, metadata=None):
        calls.append({"message": message, "reason": reason, "header": header, "metadata": metadata})
        return {"sent": False, "reason": "recorded_local", "message": message, "channels": [], **(metadata or {})}

    monkeypatch.setattr("notifier.send_notification_message", fake_send)
    state_path = tmp_path / "health_state.json"

    first = notify_health_if_needed(report, state_path=state_path, cooldown_minutes=30, now=now)
    second = notify_health_if_needed(report, state_path=state_path, cooldown_minutes=30, now=now + timedelta(minutes=5))
    saved = json.loads(state_path.read_text())

    assert first["sent"] is False
    assert first["reason"] == "recorded_local"
    assert second["sent"] is False
    assert second["reason"] == "cooldown"
    assert len(calls) == 1
    assert calls[0]["metadata"] == {"incident_key": "WARN|health"}
    assert first["incident_key"] == "WARN|health"
    assert "last_attempt_at" in saved
    assert "last_sent_at" not in saved


def test_notify_health_if_needed_cools_down_changing_premium_block_message(tmp_path, monkeypatch):
    calls = []
    now = datetime(2026, 6, 8, 12, 0, tzinfo=timezone.utc)
    base_report = {
        "status": "WARN",
        "operational_summary": {
            "mode": "PREMIUM_BLOCKED",
            "label": "Premium bloqueado",
            "safe_mode": "NO_STOCK_OR_OPTIONS_ALERTS",
            "active_route": "PARTIAL_MARKET_ROUTE",
            "active_route_label": "Operar solo CRYPTO",
            "active_route_detail": "Operable CRYPTO; bloqueado STOCK, OPTIONS.",
            "blocker_category": "MARKET_CONFIRMATION_WAIT",
            "detail": "1h confirma: Score tendencia 58 | Esperando volumen x1",
        },
        "provider_recovery": {
            "primary_provider_issue": "alpaca_auth",
            "alpaca_account_error_category": "AUTH_INVALID",
        },
    }
    changed_report = {
        **base_report,
        "operational_summary": {
            **base_report["operational_summary"],
            "detail": "1h confirma: Score tendencia 58 | Esperando volumen x2",
        },
    }

    def fake_send(message, *, reason, header, metadata=None):
        calls.append({"message": message, "reason": reason, "header": header, "metadata": metadata})
        return {"sent": False, "reason": "recorded_local", "message": message, "channels": [], **(metadata or {})}

    monkeypatch.setattr("notifier.send_notification_message", fake_send)
    state_path = tmp_path / "health_state.json"

    first = notify_health_if_needed(base_report, state_path=state_path, cooldown_minutes=30, now=now)
    second = notify_health_if_needed(
        changed_report, state_path=state_path, cooldown_minutes=30, now=now + timedelta(minutes=5)
    )
    saved = json.loads(state_path.read_text())

    assert first["reason"] == "recorded_local"
    assert second["reason"] == "cooldown"
    assert first["incident_key"] == second["incident_key"]
    assert saved["last_incident_key"] == first["incident_key"]
    assert len(calls) == 1


