    assert status["history_budget_ratio"] == 0.85
    assert status["history_budget_margin_bytes"] == 150_000
    assert status["average_history_line_bytes"] == 2000
    assert status["projected_next_line_budget_ratio"] == 0.852
    assert status["projected_next_budget_ratio"] == 0.852
