def test_function_source_by_name_extracts_function_without_ast_source_segment():
    source = "\n".join(
        [
            "def first():",
            "    return 'first'",
            "",
            "def target(value):",
            "    if value:",
            "        return 'yes'",
            "    return 'no'",
            "",
            "def last():",
            "    return 'last'",
        ]
    )

    extracted = _function_source_by_name(source, "target")

    assert extracted.startswith("def target(value):")
    assert "return 'yes'" in extracted
    assert "def first" not in extracted
    assert "def last" not in extracted


