def test_streamlit_app_needs_recovery_detects_failed_app_check():
    assert streamlit_app_needs_recovery({"checks": []}) is True
    assert streamlit_app_needs_recovery({"checks": [{"name": "streamlit_app", "status": "FAIL"}]}) is True
    assert streamlit_app_needs_recovery({"checks": [{"name": "streamlit_app", "status": "WARN"}]}) is True
    assert (
        streamlit_app_needs_recovery(
            {"checks": [{"name": "streamlit_app", "status": "OK", "status_code": 200, "recent_critical": []}]}
        )
        is False
    )


def test_streamlit_app_needs_recovery_for_structural_risk_even_if_status_ok():
    base = {"name": "streamlit_app", "status": "OK", "status_code": 200, "recent_critical": []}
    risky_checks = [
        {"status_code": 500},
        {"recent_critical": [{"path": "streamlit.err", "line": "RuntimeError"}]},
        {"detail": "App not reachable: connection refused"},
        {"detail": "App check failed: timeout"},
        {"detail": "HTTP 200, recent Streamlit log critical: RuntimeError"},
    ]
    for fields in risky_checks:
        assert streamlit_app_needs_recovery({"checks": [{**base, **fields}]}) is True


def test_recover_streamlit_app_restarts_launchagent_without_wait(monkeypatch):
    monkeypatch.setattr(
        "tools.launchd_recovery.restart_launch_agent",
        lambda module_name: {"action": "restart", "ok": True, "module": module_name},
    )

    result = recover_streamlit_app(wait_seconds=0, allow_direct_fallback=False)

    assert result["action"] == "restart"
    assert result["ok"] is True
    assert result["module"] == "tools.streamlit_launchd"
    assert result["app_url"] == "http://127.0.0.1:3000"
    assert result["ready"] in {True, False}


def test_recover_streamlit_app_starts_direct_fallback_when_launchagent_is_not_ready(monkeypatch):
    probes = iter(
        [
            {"status": "FAIL", "detail": "App not reachable"},
            {"status": "OK", "detail": "App reachable"},
        ]
    )
    monkeypatch.setattr(
        "tools.launchd_recovery.restart_launch_agent",
        lambda module_name: {"action": "restart", "ok": True, "module": module_name},
    )
    monkeypatch.setattr(
        "tools.roxy_realtime_check.validate_app_url",
        lambda *args, **kwargs: next(probes),
    )
    monkeypatch.setattr(
        "tools.roxy_realtime_check.start_streamlit_direct",
        lambda: {"action": "started_direct", "ok": True, "pid": 123},
    )

    result = recover_streamlit_app(wait_seconds=0)

    assert result["ready"] is True
    assert result["direct_fallback"] == {"action": "started_direct", "ok": True, "pid": 123}


