def test_output_maintenance_report_needs_recovery_for_warn_or_fail():
    assert output_maintenance_report_needs_recovery({"checks": []})
    assert output_maintenance_report_needs_recovery(
        {"checks": [{"name": "output_maintenance_report", "status": "WARN"}]}
    )
    assert output_maintenance_report_needs_recovery(
        {"checks": [{"name": "output_maintenance_report", "status": "FAIL"}]}
    )
    assert not output_maintenance_report_needs_recovery(
        {
            "checks": [
                {
                    "name": "output_maintenance_report",
                    "status": "OK",
                    "dry_run": False,
                    "output_exists": True,
                    "operation_protected": True,
                    "output_archive_error_count": 0,
                    "footprint_budget_status": "OK",
                    "maintenance_contract_issues": [],
                    "runtime_footprint_mb": 53.5,
                    "output_footprint_mb": 40.0,
                    "alerts_footprint_mb": 3.5,
                    "logs_footprint_mb": 10.0,
                    "dashboard_history_after_rows": 120,
                    "dashboard_history_max_rows": 5000,
                    "max_history_bytes": 7500000,
                    "min_history_lines": 120,
                    "hygiene_status": "OK",
                    "operation_status": "OK",
                }
            ]
        }
    )


def _healthy_output_maintenance_check(**overrides):
    item = {
        "name": "output_maintenance_report",
        "status": "OK",
        "dry_run": False,
        "output_exists": True,
        "operation_protected": True,
        "output_archive_error_count": 0,
        "footprint_budget_status": "OK",
        "maintenance_contract_issues": [],
        "runtime_footprint_mb": 53.5,
        "output_footprint_mb": 40.0,
        "alerts_footprint_mb": 3.5,
        "logs_footprint_mb": 10.0,
        "dashboard_history_after_rows": 120,
        "dashboard_history_max_rows": 5000,
        "max_history_bytes": 7500000,
        "min_history_lines": 120,
        "hygiene_status": "OK",
        "operation_status": "OK",
        "history_budget_status": "OK",
        "history_budget_pressure": "CLEAR",
    }
    item.update(overrides)
    return item


def test_output_maintenance_report_needs_recovery_for_structural_issues_even_if_status_ok():
    base = {"name": "output_maintenance_report", "status": "OK"}
    issue_fields = [
        {"dry_run": True},
        {"output_exists": False},
        {"operation_protected": False},
        {"output_archive_error_count": 1},
        {"footprint_budget_status": "WARN"},
        {"history_budget_status": "WARN"},
        {"history_budget_pressure": "NEAR_LIMIT"},
        {"maintenance_contract_issues": ["maintenance status alias missing"]},
        {"runtime_footprint_mb": None},
        {"output_footprint_mb": None},
        {"alerts_footprint_mb": None},
        {"logs_footprint_mb": None},
        {"dashboard_history_after_rows": None},
        {"dashboard_history_max_rows": None},
        {"max_history_bytes": None},
        {"min_history_lines": None},
        {"hygiene_status": ""},
        {"operation_status": ""},
    ]
    for fields in issue_fields:
        assert output_maintenance_report_needs_recovery({"checks": [{**base, **fields}]})

    assert not output_maintenance_report_needs_recovery(
        {
            "checks": [
                {
                    **base,
                    "dry_run": False,
                    "output_exists": True,
                    "operation_protected": True,
                    "output_archive_error_count": 0,
                    "footprint_budget_status": "OK",
                    "maintenance_contract_issues": [],
                    "runtime_footprint_mb": 53.5,
                    "output_footprint_mb": 40.0,
                    "alerts_footprint_mb": 3.5,
                    "logs_footprint_mb": 10.0,
                    "dashboard_history_after_rows": 120,
                    "dashboard_history_max_rows": 5000,
                    "max_history_bytes": 7500000,
                    "min_history_lines": 120,
                    "hygiene_status": "OK",
                    "operation_status": "OK",
                }
            ]
        }
    )


