def test_dashboard_render_probe_needs_recovery_for_missing_or_bad_probe():
    assert dashboard_render_probe_needs_recovery({"checks": []})
    assert dashboard_render_probe_needs_recovery(
        {"checks": [{"name": "dashboard_render_probe", "status": "OK", "age_minutes": 3.0}]}
    )
    assert dashboard_render_probe_needs_recovery(
        {"checks": [{"name": "dashboard_search_render_probe", "status": "OK", "age_minutes": 3.0}]}
    )
    assert dashboard_render_probe_needs_recovery({"checks": [{"name": "dashboard_render_probe", "status": "INFO"}]})
    assert dashboard_render_probe_needs_recovery({"checks": [{"name": "dashboard_render_probe", "status": "WARN"}]})
    assert dashboard_render_probe_needs_recovery({"checks": [{"name": "dashboard_render_probe", "status": "FAIL"}]})
    assert dashboard_render_probe_needs_recovery(
        {
            "checks": [
                {"name": "dashboard_render_probe", "status": "OK"},
                {"name": "dashboard_search_render_probe", "status": "WARN"},
            ]
        }
    )
    assert not dashboard_render_probe_needs_recovery(
        {
            "checks": [
                {"name": "dashboard_render_probe", "status": "OK", "age_minutes": 3.0},
                {"name": "dashboard_search_render_probe", "status": "OK", "age_minutes": 3.0},
            ]
        }
    )


