def test_dashboard_render_probe_needs_recovery_for_structural_risk_even_if_status_ok():
    healthy_search = {"name": "dashboard_search_render_probe", "status": "OK", "age_minutes": 3.0}
    base = {
        "name": "dashboard_render_probe",
        "status": "OK",
        "age_minutes": 3.0,
        "probe_status": "OK",
        "frontend_error_status": "OK",
        "text_length": 1200,
        "min_text_length": 500,
    }
    risky_checks = [
        {"malformed": True},
        {"exists": False},
        {"probe_status": "FAIL"},
        {"frontend_error_status": "WARN"},
        {"black_screen": True},
        {"live_no_reload": False},
        {"view_persisted": False},
        {"selected_view_persisted": False},
        {"symbol_persisted": False},
        {"market_persisted": False},
        {"timeframe_persisted": False},
        {"missing_required_text": ["Roxy Trading"]},
        {"forbidden_text_found": ["Traceback"]},
        {"blocking_console_error_count": 1},
        {"fatal_console_error_count": 1},
        {"blocking_console_warning_count": 1},
        {"blocking_page_error_count": 1},
        {"text_length": 499},
        {"contract_version": 2, "final_symbol": "BONK/USD", "selected_symbol": ""},
        {"contract_version": 2, "final_market": "crypto", "selected_market": ""},
        {"contract_version": 2, "final_timeframe": "1h", "selected_timeframe": ""},
    ]
    for fields in risky_checks:
        assert dashboard_render_probe_needs_recovery(
            {"checks": [{**base, **fields}, healthy_search]},
            max_ok_age_minutes=45.0,
        )

    assert not dashboard_render_probe_needs_recovery(
        {
            "checks": [
                {
                    **base,
                    "black_screen": False,
                    "live_no_reload": True,
                    "view_persisted": True,
                    "selected_view_persisted": True,
                    "symbol_persisted": True,
                    "market_persisted": True,
                    "timeframe_persisted": True,
                    "missing_required_text": [],
                    "forbidden_text_found": [],
                    "blocking_console_error_count": 0,
                    "fatal_console_error_count": 0,
                    "blocking_console_warning_count": 0,
                    "contract_version": 2,
                    "final_symbol": "BONK/USD",
                    "selected_symbol": "BONK/USD",
                    "final_market": "crypto",
                    "selected_market": "crypto",
                    "final_timeframe": "1h",
                    "selected_timeframe": "1h",
                    "blocking_page_error_count": 0,
                },
                healthy_search,
            ]
        },
        max_ok_age_minutes=45.0,
    )


