def test_ensure_output_maintenance_report_regenerates_report(tmp_path):
    output = tmp_path / "output"
    alerts = tmp_path / "alerts"
    logs = tmp_path / "logs"
    output.mkdir()
    alerts.mkdir()
    logs.mkdir()
    cache_dir = tmp_path / "Library" / "Caches"
    cache_dir.mkdir(parents=True)
    old_cache = cache_dir / "old.cache"
    old_cache.write_text("old")
    os.utime(old_cache, (1, 1))
    (alerts / "local_storage_pressure_sources.json").write_text(
        json.dumps(
            {
                "check": {
                    "status": "INFO",
                    "cleanup_plan_state": "SAFE_CACHE_REVIEW_READY",
                    "cleanup_automation_ready": True,
                    "safe_cleanup_entries": [{"name": "Library/Caches", "path": str(cache_dir)}],
                }
            }
        )
    )
    old_path = output / "stocks_tech_20260606_000000.csv"
    new_path = output / "stocks_tech_20260607_000000.csv"
    old_path.write_text("old")
    new_path.write_text("new")
    os.utime(old_path, (1, 1))
    os.utime(new_path, (2, 2))
    old_report = alerts / "weekly_report_20260601_090000.txt"
    newer_report = alerts / "weekly_report_20260608_090000.txt"
    old_report.write_text("old")
    newer_report.write_text("new")
    os.utime(old_report, (1, 1))
    os.utime(newer_report, (2, 2))

    result = ensure_output_maintenance_report(
        output_path=output,
        alerts_path=alerts,
        report_path=alerts / "output_maintenance.json",
        text_path=alerts / "output_maintenance.txt",
        log_dirs=[logs],
    )

    assert result["action"] == "regenerated"
    assert result["ok"] is True
    assert result["output_archive_count"] == 0
    assert result["removed_alert_report_count"] == 0
    assert result["local_cache_cleanup_status"] == "DONE"
    assert result["local_cache_cleanup_enabled"] is True
    assert result["local_cache_cleanup_plan_state"] == "SAFE_CACHE_REVIEW_READY"
    assert result["local_cache_cleanup_removed_count"] == 1
    assert not old_cache.exists()
    assert (alerts / "output_maintenance.json").exists()
    assert (alerts / "output_maintenance.txt").exists()
    payload = json.loads((alerts / "output_maintenance.json").read_text())
    assert payload["output_dir"] == str(output)
    expected_history_limit = int(DEFAULT_HEALTH_HISTORY_MAX_BYTES)
    assert result["max_history_bytes"] == expected_history_limit
    assert payload["max_history_bytes"] == expected_history_limit
    assert payload["local_cache_cleanup_status"] == "DONE"
    assert payload["local_cache_cleanup_enabled"] is True


def test_ensure_dashboard_render_probe_report_runs_probe_script(tmp_path, monkeypatch):
    alerts = tmp_path / "alerts"
    alerts.mkdir()
    (tmp_path / "output").mkdir()
    (alerts / "roxy_status.json").write_text(
        json.dumps(
            {
                "operational_focus_symbol": "BONK/USD",
                "top_symbol": "ETH/USD",
                "daily_plan_top_symbol": "ETH/USD",
            }
        )
    )
    captured = {"urls": [], "required": []}

    def fake_run(cmd, cwd, text, capture_output, timeout):
        captured["urls"].append(cmd[cmd.index("--url") + 1])
        captured["required"].append([cmd[idx + 1] for idx, value in enumerate(cmd) if value == "--required-text"])
        report_path = Path(cmd[cmd.index("--json-path") + 1])
        is_search = report_path.name == "dashboard_render_probe_search.json"
        report_path.write_text(
            json.dumps(
                {
                    "generated_at": "2026-06-08T12:00:00+00:00",
                    "status": "OK",
                    "detail": "render OK",
                    "text_length": 2345 if is_search else 1234,
                    "contract_version": 2,
                    "black_screen": False,
                    "live_no_reload": True,
                    "view_persisted": True,
                    "selected_view_persisted": True,
                    "symbol_persisted": True,
                    "market_persisted": True,
                    "timeframe_persisted": True,
                    "final_url": (
                        "http://127.0.0.1:3000/?view=Dashboard&symbol=AAPL&market=stock&tf=1h"
                        if is_search
                        else "http://127.0.0.1:3000/?view=Dashboard&symbol=BONK%2FUSD&market=crypto&tf=1h"
                    ),
                    "final_symbol": "AAPL" if is_search else "BONK/USD",
                    "selected_symbol": "AAPL" if is_search else "BONK/USD",
                    "final_market": "stock" if is_search else "crypto",
                    "selected_market": "stock" if is_search else "crypto",
                    "final_timeframe": "1h",
                    "selected_timeframe": "1h",
                }
            )
        )
        return type("Result", (), {"returncode": 0, "stdout": "done", "stderr": ""})()

    monkeypatch.setattr(roxy_realtime_check.subprocess, "run", fake_run)

    result = ensure_dashboard_render_probe_report(
        base_dir=tmp_path,
        app_url="http://127.0.0.1:3000",
        timeout_seconds=99,
    )

    assert result["ok"] is True
    assert result["status"] == "OK"
    assert result["text_length"] == 1234
    assert result["black_screen"] is False
    assert result["live_no_reload"] is True
    assert result["selected_view_persisted"] is True
    assert result["contract_version"] == 2
    assert result["selected_symbol"] == "BONK/USD"
    assert result["selected_market"] == "crypto"
    assert result["selected_timeframe"] == "1h"
    assert result["report_path"].endswith("dashboard_render_probe.json")
    assert result["screenshot_path"].endswith("dashboard_render_probe.png")
    assert result["search_report_path"].endswith("dashboard_render_probe_search.json")
    assert result["search"]["ok"] is True
    assert result["search"]["symbol_persisted"] is True
    assert result["search"]["selected_symbol"] == "AAPL"
    assert result["search"]["selected_market"] == "stock"
    assert result["search"]["selected_timeframe"] == "1h"
    assert result["search"]["market_persisted"] is True
    assert result["search"]["timeframe_persisted"] is True
    assert captured["urls"] == [
        "http://127.0.0.1:3000/?view=Dashboard&symbol=BONK%2FUSD&market=crypto&tf=1h",
        "http://127.0.0.1:3000/?view=Dashboard&symbol=AAPL&market=stock&tf=1h",
    ]
    assert captured["required"][0] == ["Live sin reload", "Dashboard", "BONK/USD", "Roxy Trading"]
    assert captured["required"][1] == ["Live sin reload", "Dashboard", "AAPL", "Roxy Trading"]


