def test_validate_runtime_backup_report_retries_transient_permission_error(tmp_path, monkeypatch):
    now = datetime(2026, 6, 10, 12, 0, tzinfo=timezone.utc)
    base = tmp_path / "project"
    alerts = base / "alerts"
    db = base / "db"
    alerts.mkdir(parents=True)
    db.mkdir()
    (alerts / "roxy_realtime_check.json").write_text("{}")
    (alerts / "runtime_backup.json").write_text("{}")
    (db / "scan_history.csv").write_text("ts,market,symbol,tf,signal,score\n")
    (db / "roxy.db").write_text("db")
    archive_path = tmp_path / "external" / "roxy_runtime_20260610_110000.tar.gz"
    archive_path.parent.mkdir()
    with tarfile.open(archive_path, "w:gz") as archive:
        archive.add(alerts, arcname="alerts")
        archive.add(db, arcname="db")
    report = alerts / "runtime_backup.json"
    report.write_text(
        json.dumps(
            {
                "generated_at": now.isoformat(),
                "status": "OK",
                "archive_path": str(archive_path),
                "archive_exists": True,
                "archive_size_bytes": archive_path.stat().st_size,
                "include_paths": ["alerts", "db"],
                "dry_run": False,
            }
        )
    )
    real_open = roxy_realtime_check.tarfile.open
    calls = 0

    def flaky_open(*args, **kwargs):
        nonlocal calls
        calls += 1
        if calls == 1:
            raise PermissionError("Operation not permitted")
        return real_open(*args, **kwargs)

    monkeypatch.setattr(roxy_realtime_check.tarfile, "open", flaky_open)
    monkeypatch.setattr(roxy_realtime_check.time, "sleep", lambda _seconds: None)

    status = validate_runtime_backup_report(report, now=now)

    assert calls == 2
    assert status["status"] == "OK"
    assert status["archive_readable"] is True
    assert status["archive_verified"] is True
    assert status["archive_verification_error"] == ""
    assert status["archive_verification_source"] == "runtime"
    assert status["archive_missing_critical_members"] == []


