def test_runtime_backup_report_needs_recovery_for_warn_or_fail():
    assert runtime_backup_report_needs_recovery({"checks": []})
    assert runtime_backup_report_needs_recovery({"checks": [{"name": "runtime_backup_report", "status": "WARN"}]})
    assert runtime_backup_report_needs_recovery({"checks": [{"name": "runtime_backup_report", "status": "FAIL"}]})
    assert not runtime_backup_report_needs_recovery(
        {
            "checks": [
                {
                    "name": "runtime_backup_report",
                    "status": "OK",
                    "archive_path": "/tmp/roxy_runtime.tar.gz",
                    "archive_exists": True,
                    "archive_readable": True,
                    "archive_verified": True,
                    "archive_size_bytes": 123,
                    "archive_missing_verified_paths": [],
                    "age_hours": 1.0,
                    "max_age_hours": 30.0,
                }
            ]
        }
    )


def test_runtime_backup_report_needs_recovery_for_structural_risk_even_if_status_ok():
    base = {"name": "runtime_backup_report", "status": "OK", "archive_size_bytes": 123}
    risky_checks = [
        {"malformed": True},
        {"dry_run": True},
        {"archive_exists": False},
        {"archive_readable": False},
        {"archive_verified": False},
        {"archive_path": ""},
        {"archive_size_bytes": 0},
        {"archive_missing_verified_paths": ["db"]},
        {"archive_missing_critical_members": ["alerts/roxy_realtime_check.json"]},
        {"archive_database_member_verified": False},
        {"archive_verified": False, "archive_verification_error": "TarError: bad archive"},
        {"age_hours": None, "max_age_hours": 30.0},
        {"age_hours": 1.0, "max_age_hours": None},
        {"age_hours": 31.0, "max_age_hours": 30.0},
    ]
    for fields in risky_checks:
        assert runtime_backup_report_needs_recovery({"checks": [{**base, **fields}]})

    assert not runtime_backup_report_needs_recovery(
        {
            "checks": [
                {
                    **base,
                    "malformed": False,
                    "dry_run": False,
                    "archive_path": "/tmp/roxy_runtime.tar.gz",
                    "archive_exists": True,
                    "archive_readable": True,
                    "archive_verified": True,
                    "archive_missing_verified_paths": [],
                    "archive_missing_critical_members": [],
                    "archive_database_member_verified": True,
                    "archive_verification_error": "",
                    "age_hours": 8.0,
                    "max_age_hours": 30.0,
                }
            ]
        }
    )


