def test_validate_local_storage_pressure_sources_reports_top_candidates(tmp_path):
    downloads = tmp_path / "Downloads"
    caches = tmp_path / "Library" / "Caches"
    desktop = tmp_path / "Desktop"
    downloads.mkdir()
    caches.mkdir(parents=True)
    desktop.mkdir()
    (downloads / "large.bin").write_text("x" * 40)
    (caches / "cache.bin").write_text("y" * 25)
    (desktop / "small.txt").write_text("z" * 5)

    status = validate_local_storage_pressure_sources(
        home_dir=tmp_path,
        free_pct=24.5,
        candidate_relpaths=("Downloads", "Library/Caches", "Desktop", "Missing"),
        top_limit=2,
    )

    assert status["status"] == "INFO"
    assert status["pressure_active"] is True
    assert status["candidate_count"] == 3
    assert status["missing_candidate_count"] == 1
    assert [item["name"] for item in status["top_entries"]] == ["Downloads", "Library/Caches"]
    assert status["top_entries"][0]["size_bytes"] == 40
    assert status["top_entries"][0]["cleanup_policy"] == "MANUAL_REVIEW_REQUIRED"
    assert status["top_entries"][1]["cleanup_policy"] == "SAFE_CACHE_REVIEW"
    assert status["manual_review_entries"][0]["name"] == "Downloads"
    assert status["safe_cleanup_entries"][0]["name"] == "Library/Caches"
    assert status["cleanup_action"] == (
        "Review user storage manually: Downloads 0.0GiB. Safe cache candidates: Library/Caches 0.0GiB."
    )
    assert status["cleanup_plan_state"] == "MANUAL_REVIEW_REQUIRED"
