def test_validate_project_storage_footprint_surfaces_video_ingest_staging(tmp_path, monkeypatch):
    staging = tmp_path / "data" / "video_ingest_staging"
    staging.mkdir(parents=True)
    (staging / "lesson.mp4").write_text("video")

    original_path_size_bytes = roxy_realtime_check.path_size_bytes

    def fake_path_size_bytes(path):
        path = Path(path)
        if path == tmp_path / "data" or path == staging:
            return 3 * 1024**3
        return original_path_size_bytes(path)

    monkeypatch.setattr(roxy_realtime_check, "path_size_bytes", fake_path_size_bytes)

    status = validate_project_storage_footprint(tmp_path, warn_size_gb=1, fail_size_gb=2)

    assert status["status"] == "FAIL"
    assert status["video_ingest_staging_exists"] is True
    assert status["video_ingest_staging_size_gb"] == 3.0
    assert status["video_ingest_staging_archive_suggestion"].endswith("/RoxyVideosAnalizados")
    assert "staging video data/video_ingest_staging 3.00 GiB" in status["detail"]


