def test_validate_chart_provider_effective_warns_on_alpaca_auth_fallback(monkeypatch):
    monkeypatch.setattr(
        "symbol_detail.fetch_symbol_history_with_source",
        lambda symbol, market, timeframe: (
            pd.DataFrame({"close": [1, 2]}),
            {
                "provider": "yfinance",
                "source": "yfinance",
                "mode": "FALLBACK",
                "fallback": True,
                "fallback_reason": "alpaca_auth",
                "fallback_detail": "Alpaca rechazo las credenciales o el token.",
                "fallback_action": "Revisar credenciales Alpaca.",
                "polygon_fallback_reason": "polygon_not_configured",
                "polygon_fallback_action": "Configurar Polygon.",
            },
        ),
    )

    status = validate_chart_provider_effective("WMT", "stock", "1h")

