    assert status["fallback"] is True
    assert status["fallback_reason"] == "alpaca_auth"
    assert status["polygon_fallback_reason"] == "polygon_not_configured"
    assert "POLYGON_API_KEY" in status["premium_recovery_action"]
    assert "premium provider fallback alpaca_auth" in status["detail"]
    assert "alternate polygon_not_configured" in status["detail"]


