def test_validate_chart_providers_effective_warns_when_active_stock_falls_back(monkeypatch):
    def fake_fetch(symbol, market, timeframe):
        if symbol == "ETH/USD":
            return (
                pd.DataFrame({"close": [1, 2]}),
                {
                    "provider": "ccxt",
                    "source": "ccxt:binanceus",
                    "mode": "EXCHANGE_API",
                    "fallback": False,
                },
            )
        return (
            pd.DataFrame({"close": [1, 2]}),
            {
                "provider": "yfinance",
                "source": "yfinance",
                "mode": "FALLBACK",
                "fallback": True,
                "fallback_reason": "alpaca_auth",
                "polygon_fallback_reason": "polygon_not_configured",
                "polygon_fallback_action": "Configurar Polygon.",
            },
        )

    monkeypatch.setattr("symbol_detail.fetch_symbol_history_with_source", fake_fetch)

    status = validate_chart_providers_effective(
        [("ETH/USD", "crypto"), ("WMT", "stock")],
        timeframe="1h",
    )

    assert status["status"] == "WARN"
    assert status["checked_count"] == 2
    assert status["fallback_count"] == 1
    assert status["auth_fallback_count"] == 1
    assert status["polygon_missing_count"] == 1
    assert status["market_issue_counts"] == {"stock": 1}
    assert status["market_checked_counts"] == {"crypto": 1, "stock": 1}
    assert status["stock_issue_count"] == 1
    assert status["crypto_issue_count"] == 0
    assert status["stock_auth_fallback_count"] == 1
    assert status["crypto_fallback_count"] == 0
    assert status["operable_market_issue_count"] == 0
    assert status["blocked_market_issue_count"] == 1
    assert status["route_focus_label"] == "Crypto operable; stock/options bloqueado"
    assert status["fallback_reason_counts"] == {"alpaca_auth": 1}
    assert status["alternate_reason_counts"] == {"polygon_not_configured": 1}
    assert "issue WMT 1h alpaca_auth, alternate polygon_not_configured" in status["detail"]
    assert (
        status["premium_recovery_action"]
        == "Configurar POLYGON_API_KEY/POLYGON_API_TOKEN o corregir credenciales Alpaca para recuperar velas premium."
    )


