def test_validate_alpaca_account_probe_reports_endpoint_mode_hint():
    calls = {}

    class Client:
        def __init__(self, **kwargs):
            calls.update(kwargs)

        def get_account(self):
            raise RuntimeError("403 Forbidden endpoint paper/live mismatch")

    status = validate_alpaca_account_probe(
        env={
            "ALPACA_API_KEY": "paper-key",
            "ALPACA_API_SECRET": "paper-secret",
            "ALPACA_PAPER": "true",
            "ALPACA_BASE_URL": "https://api.alpaca.markets",
        },
        client_factory=Client,
    )

    assert status["status"] == "WARN"
    assert status["auth_ok"] is False
    assert status["error_category"] == "AUTH_FORBIDDEN"
    assert status["mode"] == "paper"
    assert status["expected_endpoint"] == "https://paper-api.alpaca.markets"
    assert status["endpoint_mode_hint"] == "ALPACA_PAPER=true pero endpoint override no parece paper."
    assert status["url_override_configured"] is True
    assert status["url_override_ignored"] is True
    assert status["effective_endpoint"] == "https://paper-api.alpaca.markets"
    assert "url_override" not in calls
    assert "paper-key" not in str(status)
    assert "paper-secret" not in str(status)


def test_validate_alpaca_account_probe_times_out_without_blocking_health():
    class Client:
        def __init__(self, **kwargs):
            pass

        def get_account(self):
            time.sleep(0.2)
            return object()

    started = time.monotonic()
    status = validate_alpaca_account_probe(
        env={"ALPACA_API_KEY": "slow-key", "ALPACA_API_SECRET": "slow-secret", "ALPACA_PAPER": "true"},
        client_factory=Client,
        timeout_seconds=0.01,
    )
    elapsed = time.monotonic() - started

    assert elapsed < 0.15
    assert status["status"] == "INFO"
    assert status["auth_ok"] is None
    assert status["diagnosis"] == "alpaca_account_probe_timeout"
    assert status["expected_endpoint"] == "https://paper-api.alpaca.markets"
    assert "slow-key" not in str(status)
    assert "slow-secret" not in str(status)


