def test_validate_chart_providers_effective_dedupes_targets(monkeypatch):
    calls = []

    def fake_fetch(symbol, market, timeframe):
        calls.append((symbol, market, timeframe))
        if market == "crypto":
            return (
                pd.DataFrame({"close": [1, 2]}),
                {
                    "provider": "ccxt",
                    "source": "ccxt:binanceus",
                    "mode": "EXCHANGE_API",
                    "fallback": False,
                },
            )
        return (
            pd.DataFrame({"close": [1, 2]}),
            {
                "provider": "Alpaca",
                "source": "alpaca_iex",
                "mode": "BROKER_DATA",
                "fallback": False,
            },
        )

    monkeypatch.setattr("symbol_detail.fetch_symbol_history_with_source", fake_fetch)

    status = validate_chart_providers_effective(
        [("AAPL", "stock"), ("AAPL", "stock"), ("BTC/USD", "crypto")],
        timeframe="1h",
    )

    assert status["status"] == "OK"
    assert status["checked_count"] == 2
    assert calls == [("AAPL", "stock", "1h"), ("BTC/USD", "crypto", "1h")]


def test_validate_chart_providers_effective_reports_info_for_expected_fallback(monkeypatch):
    def fake_fetch(symbol, market, timeframe):
        if market == "crypto":
            return (
                pd.DataFrame({"close": [1, 2]}),
                {"provider": "ccxt", "source": "ccxt:binanceus", "mode": "EXCHANGE_API", "fallback": False},
            )
        return (
            pd.DataFrame({"close": [1, 2]}),
            {
                "provider": "yfinance",
                "source": "yfinance",
                "mode": "FALLBACK",
                "fallback": True,
                "fallback_reason": "alpaca_not_configured",
            },
        )

    monkeypatch.setattr("symbol_detail.fetch_symbol_history_with_source", fake_fetch)

    status = validate_chart_providers_effective(
        [("ETH/USD", "crypto"), ("WMT", "stock")],
        timeframe="1h",
    )

    assert status["status"] == "INFO"
    assert status["fallback_count"] == 1
    assert status["auth_fallback_count"] == 0
    assert status["fallback_reason_counts"] == {"alpaca_not_configured": 1}
    assert "alpaca_not_configured x1" in status["detail"]


def test_validate_chart_providers_effective_passes_effective_env(monkeypatch):
    seen_env = {}

    def fake_fetch(symbol, market, timeframe, env=None):
        seen_env.update(env or {})
        return (
            pd.DataFrame({"close": [1, 2]}),
            {
                "provider": "Alpaca",
                "source": "alpaca_iex",
                "mode": "BROKER_DATA",
                "fallback": False,
            },
        )

    monkeypatch.setattr("symbol_detail.fetch_symbol_history_with_source", fake_fetch)

    status = validate_chart_providers_effective(
        [("AAPL", "stock")],
        timeframe="1h",
        env={"ALPACA_API_KEY": "key", "ALPACA_API_SECRET": "secret"},
    )

    assert status["status"] == "OK"
    assert seen_env["ALPACA_API_KEY"] == "key"
    assert seen_env["ALPACA_API_SECRET"] == "secret"


def test_validate_provider_env_parity_reports_launchd_only_alpaca(tmp_path):
    env_path = tmp_path / ".env"
    env_path.write_text(
        "\n".join(
            [
                "ALPACA_API_KEY=paper-key",
                "ALPACA_API_SECRET=paper-secret",
                "ALPACA_PAPER=true",
            ]
        )
    )

    status = validate_provider_env_parity(
        launchd_env_path=env_path,
        process_env={},
    )

    assert status["status"] == "OK"
    assert status["launchd_alpaca_configured"] is True
    assert status["process_alpaca_configured"] is False
    assert status["launchd_premium_configured"] is True
    assert status["process_premium_configured"] is False
    assert status["launchd_provider_keys"] == ["ALPACA_API_KEY", "ALPACA_API_SECRET", "ALPACA_PAPER"]
    assert "paper-key" not in str(status)
    assert status["effective_alpaca_configured"] is True
    assert status["effective_premium_configured"] is True
    assert status["effective_loaded_provider_keys"] == ["ALPACA_API_KEY", "ALPACA_API_SECRET", "ALPACA_PAPER"]
    assert "effective service context" in status["detail"]


