def test_ensure_chart_health_report_regenerates_report(tmp_path, monkeypatch):
    report_path = tmp_path / "chart_realtime_health.json"

    def fake_collect_chart_health(*, symbols, timeframes, now=None):
        return [
            {
                "symbol": symbols[0],
                "market": "stock",
                "timeframe": timeframes[0],
                "status": "OK",
                "label": "Live",
                "tone": "buy",
                "detail": "fresh",
                "rows": 200,
                "has_rsi": True,
                "has_macd": True,
                "indicator_status": "OK",
            }
        ]

    monkeypatch.setattr("tools.chart_realtime_health.collect_chart_health", fake_collect_chart_health)

    result = ensure_chart_health_report(report_path=report_path, symbols=["AAPL"], timeframes=["1h"])

    assert result["action"] == "regenerated"
    assert result["status"] == "OK"
    assert result["summary_status"] == "OK"
    assert result["missing_required_chart_symbol_count"] == 0
    assert result["checked_count"] == 1
    assert report_path.exists()
    payload = json.loads(report_path.read_text())
    assert payload["summary"]["status"] == "OK"


def test_ensure_chart_health_report_includes_active_alert_symbols(tmp_path, monkeypatch):
    alerts = tmp_path / "alerts"
    alerts.mkdir()
    report_path = alerts / "chart_realtime_health.json"
    (alerts / "roxy_status.json").write_text(json.dumps({"top_symbol": "WMT"}))
    captured = {}

    def fake_collect_chart_health(*, symbols, timeframes, now=None):
        captured["symbols"] = list(symbols)
        return [
            {
                "symbol": symbol,
                "market": "stock",
                "timeframe": timeframes[0],
                "status": "OK",
                "label": "Live",
                "tone": "buy",
                "detail": "fresh",
                "rows": 200,
                "has_rsi": True,
                "has_macd": True,
                "indicator_status": "OK",
            }
            for symbol in symbols
        ]

    monkeypatch.setattr("tools.chart_realtime_health.collect_chart_health", fake_collect_chart_health)

    result = ensure_chart_health_report(report_path=report_path, timeframes=["1h"])

    assert result["action"] == "regenerated"
    assert result["status"] == "OK"
    assert "WMT" in captured["symbols"]
    assert result["active_symbols"] == ["WMT"]
    assert result["missing_required_chart_symbols"] == []


