def test_live_data_needs_recovery_for_structural_risk_even_if_status_ok():
    healthy_checks = [
        {
            "name": "heartbeat",
            "status": "OK",
            "exists": True,
            "malformed": False,
            "heartbeat_status": "SUCCESS",
            "duration_seconds": 120.0,
            "started_at_future_minutes": 0.0,
            "duration_state": "normal",
            "success_warn_seconds": 600.0,
            "success_fail_seconds": 900.0,
        },
        {"name": "live_backend_process_guard", "status": "OK", "duplicate_count": 0, "duplicate_roles": []},
        {"name": "live_scan_freshness", "status": "OK", "age_minutes": 4.0, "max_age_minutes": 10.0},
        {"name": "confluence_freshness", "status": "OK", "age_minutes": 5.0, "max_age_minutes": 10.0},
        {"name": "live_scan_rows", "status": "OK", "rows": 12},
        {"name": "timeframe_coverage", "status": "OK", "present": ["15m", "1h", "2h", "4h"], "missing": []},
        {"name": "confluence_rows", "status": "OK", "rows": 8},
        {"name": "higher_timeframe_confluence", "status": "OK", "missing_columns": []},
        {"name": "ai_brief", "status": "OK", "source_lag_minutes": 0.8, "max_source_lag_minutes": 2.0},
    ]
    assert not live_data_needs_recovery({"checks": healthy_checks})

    risky_overrides = [
        ("heartbeat", {"duration_state": "slow"}),
        ("heartbeat", {"slow_success": True}),
        ("heartbeat", {"running_state": "stuck"}),
        ("heartbeat", {"started_at_future_minutes": 6.0}),
        ("heartbeat", {"duration_seconds": 601.0, "success_warn_seconds": 600.0}),
        ("heartbeat", {"running_minutes": 16.0, "running_warn_minutes": 15.0}),
        ("live_backend_process_guard", {"duplicate_count": 1}),
        ("live_backend_process_guard", {"duplicate_roles": ["ma_live"]}),
        ("live_scan_freshness", {"age_minutes": 11.0, "max_age_minutes": 10.0}),
        ("live_scan_freshness", {"modified_future_minutes": 6.0}),
        ("confluence_freshness", {"age_minutes": 11.0, "max_age_minutes": 10.0}),
        ("confluence_freshness", {"modified_future_minutes": 6.0}),
        ("live_scan_rows", {"rows": 0}),
        ("timeframe_coverage", {"missing": ["4h"]}),
        ("timeframe_coverage", {"present": []}),
        ("confluence_rows", {"rows": 0}),
        ("higher_timeframe_confluence", {"missing_columns": ["trend_4h"]}),
        ("ai_brief", {"source_lag_minutes": 2.1, "max_source_lag_minutes": 2.0}),
    ]

    for check_name, override in risky_overrides:
        checks = [dict(item) for item in healthy_checks]
        for item in checks:
            if item["name"] == check_name:
                item.update(override)
                break
        assert live_data_needs_recovery({"checks": checks}), check_name


