def test_main_compacts_health_history_after_append_when_maintenance_due(tmp_path, monkeypatch, capsys):
    history_path = tmp_path / "history.jsonl"
    now = datetime.now(timezone.utc)
    rows = [
        {
            "status": "OK",
            "generated_at": (now - timedelta(minutes=20 - idx)).isoformat(),
            "pad": "x" * 220,
        }
        for idx in range(20)
    ]
    history_path.write_text("\n".join(json.dumps(row) for row in rows) + "\n")
    max_bytes = history_path.stat().st_size + 100

    def fake_evaluate_realtime_health(**kwargs):
        return {
            "generated_at": now.isoformat(),
            "status": "OK",
            "ok": True,
            "checks": [{"name": "heartbeat", "status": "OK", "detail": "done"}],
        }

    monkeypatch.setattr(roxy_realtime_check, "evaluate_realtime_health", fake_evaluate_realtime_health)
    monkeypatch.setattr(
        "sys.argv",
        [
            "roxy_realtime_check.py",
            "--no-lock",
            "--no-fail",
            "--json-path",
            str(tmp_path / "health.json"),
            "--text-path",
            str(tmp_path / "health.txt"),
            "--history-path",
            str(history_path),
            "--history-max-entries",
            "100",
            "--history-max-bytes",
            str(max_bytes),
            "--history-min-entries",
            "5",
        ],
    )

    roxy_realtime_check.main()
    capsys.readouterr()

    payload = json.loads((tmp_path / "health.json").read_text())
    post_maintenance = payload["health_history_post_append_maintenance"]
    history_check = next(item for item in payload["checks"] if item["name"] == "health_history_integrity")
    slo_check = next(item for item in payload["checks"] if item["name"] == "health_stability_slo")

    assert post_maintenance["action"] == "trimmed"
    assert post_maintenance["ok"] is True
    assert post_maintenance["removed_lines"] > 0
    assert post_maintenance["history_entry_rewritten"] is True
    assert history_check["maintenance_due"] is False
    assert history_check["budget_ratio"] < DEFAULT_HEALTH_HISTORY_MAINTENANCE_TRIGGER_RATIO
    assert history_check["post_append_maintenance_action"] == "trimmed"
    assert history_check["post_append_maintenance_ok"] is True
    assert history_check["post_append_maintenance_target_bytes"] == int(
        max_bytes * DEFAULT_HEALTH_HISTORY_MAINTENANCE_TARGET_RATIO
    )
    assert history_check["post_append_maintenance_configured_min_entries"] == post_maintenance["configured_min_entries"]
    assert history_check["post_append_maintenance_effective_min_entries"] == post_maintenance["effective_min_entries"]
    assert history_check["post_append_maintenance_min_entry_floor"] == post_maintenance["min_entry_floor"]
    assert history_check["post_append_maintenance_target_fit_entries"] == post_maintenance["target_fit_entries"]
    assert history_check["post_append_maintenance_min_entries_relaxed"] == post_maintenance["min_entries_relaxed"]
    assert history_check["post_append_maintenance_removed_lines"] == post_maintenance["removed_lines"]
    assert history_check["post_append_maintenance_removed_bytes"] == post_maintenance["removed_bytes"]
    assert history_check["post_append_maintenance_after_budget_ratio"] == post_maintenance["after_budget_ratio"]
    assert "post append trimmed plan BUDGET_PRESSURE removed" in history_check["detail"]
    assert slo_check["latest_health_history_post_append_maintenance_action"] == "trimmed"
    assert (
        slo_check["latest_health_history_post_append_maintenance_configured_min_entries"]
        == post_maintenance["configured_min_entries"]
    )
    assert (
        slo_check["latest_health_history_post_append_maintenance_effective_min_entries"]
        == post_maintenance["effective_min_entries"]
    )
    assert (
        slo_check["latest_health_history_post_append_maintenance_min_entry_floor"]
        == post_maintenance["min_entry_floor"]
    )
    assert (
        slo_check["latest_health_history_post_append_maintenance_target_fit_entries"]
        == post_maintenance["target_fit_entries"]
    )
    assert (
        slo_check["latest_health_history_post_append_maintenance_min_entries_relaxed"]
        == post_maintenance["min_entries_relaxed"]
    )
    assert "post_append trimmed" in slo_check["detail"]
    contract_check = next(item for item in payload["checks"] if item["name"] == "report_metrics_contract")
    latest_entry_contract = next(
        item for item in payload["checks"] if item["name"] == "health_history_latest_entry_contract"
    )
    assert contract_check["status"] == "OK"
    assert latest_entry_contract["status"] == "OK"
    assert latest_entry_contract["history_entry_mismatches"] == []
    assert slo_check["latest_report_metrics_contract_metrics_key_count"] == contract_check["metrics_key_count"]
    assert payload["metrics"]["report_metrics_contract_check_status"] == "OK"
    assert payload["metrics"]["report_metrics_contract_missing_alias_count"] == 0
    assert payload["metrics"]["health_history_latest_entry_contract_status"] == "OK"
    assert payload["metrics"]["health_history_latest_entry_contract_mismatch_count"] == 0
    assert (
        payload["metrics"]["health_stability_slo_latest_report_metrics_contract_metrics_key_count"]
        == payload["metrics"]["report_metrics_contract_metrics_key_count"]
    )
    latest_history = json.loads(history_path.read_text().splitlines()[-1])
    assert latest_history["metrics"]["health_history_post_append_maintenance_action"] == "trimmed"
    assert latest_history["metrics"]["health_history_post_append_maintenance_effective_min_entries"] == (
        post_maintenance["effective_min_entries"]
    )
    assert latest_history["metrics"]["health_history_post_append_maintenance_configured_min_entries"] == (
        post_maintenance["configured_min_entries"]
    )
    assert latest_history["metrics"]["health_history_post_append_maintenance_min_entries_relaxed"] == (
        post_maintenance["min_entries_relaxed"]
    )
    assert latest_history["storage_compacted"] is True
    assert latest_history["storage_removed_metric_count"] > 0
    assert not any(key.startswith("health_stability_slo_") for key in latest_history["metrics"])
    assert latest_history["checks"]["report_metrics_contract"] == "OK"
    assert latest_history["checks"]["health_history_latest_entry_contract"] == "OK"
    assert latest_history["metrics"]["report_metrics_contract_check_status"] == "OK"
    assert latest_history["metrics"]["report_metrics_contract_missing_alias_count"] == 0
    assert latest_history["metrics"]["health_history_latest_entry_contract_status"] == "OK"
    assert latest_history["metrics"]["health_history_latest_entry_contract_mismatch_count"] == 0
    assert "health_stability_slo_latest_report_metrics_contract_metrics_key_count" not in latest_history["metrics"]


