def test_main_runs_followup_output_maintenance_after_alert_quality_growth(tmp_path, monkeypatch, capsys):
    alerts = tmp_path / "alerts"
    output = tmp_path / "output"
    alerts.mkdir()
    output.mkdir()
    reports = [
        {
            "generated_at": "2026-06-10T12:00:00+00:00",
            "status": "OK",
            "ok": True,
            "checks": [
                {"name": "ai_brief", "status": "OK", "detail": "fresh"},
                {"name": "output_maintenance_report", "status": "OK", "detail": "budget ok"},
                {"name": "alert_quality_report", "status": "OK", "detail": "fresh"},
            ],
        },
        {
            "generated_at": "2026-06-10T12:00:01+00:00",
            "status": "WARN",
            "ok": False,
            "checks": [
                {"name": "ai_brief", "status": "OK", "detail": "fresh"},
                {
                    "name": "output_maintenance_report",
                    "status": "WARN",
                    "detail": "current history budget status warn",
                    "current_history_budget_status": "WARN",
                    "current_history_budget_pressure": "NEAR_LIMIT",
                    "current_history_budget_top_name": "alert_quality_history.jsonl",
                    "current_history_budget_top_status": "NEAR_LIMIT",
                    "current_history_budget_top_line_ratio": 0.85,
                },
                {"name": "alert_quality_report", "status": "OK", "detail": "fresh after growth"},
            ],
        },
        {
            "generated_at": "2026-06-10T12:00:02+00:00",
            "status": "OK",
            "ok": True,
            "checks": [
                {"name": "ai_brief", "status": "OK", "detail": "fresh"},
                {"name": "output_maintenance_report", "status": "OK", "detail": "budget clear"},
                {"name": "alert_quality_report", "status": "OK", "detail": "fresh"},
            ],
        },
    ]
    calls: list[str] = []

    def fake_evaluate_realtime_health(**kwargs):
        index = min(calls.count("health"), len(reports) - 1)
        calls.append("health")
        return dict(reports[index])

    def fake_ai_brief_report(**kwargs):
        calls.append("ai_brief")
        return {"ok": True, "action": "regenerated"}

    def fake_alert_quality_report(**kwargs):
        calls.append("alert_quality")
        return {"ok": True, "action": "regenerated"}

    def fake_output_maintenance_report(*, output_path, alerts_path, report_path):
        calls.append("output_maintenance")
        assert output_path == output
        assert alerts_path == alerts
        assert report_path == alerts / "output_maintenance.json"
        return {"ok": True, "action": "trimmed", "trimmed_history_names": ["alert_quality_history.jsonl"]}

    def fake_output_maintenance_needs_recovery(report):
        return any(
            item.get("name") == "output_maintenance_report" and item.get("status") == "WARN"
            for item in report.get("checks", [])
        )

    monkeypatch.setattr(roxy_realtime_check, "evaluate_realtime_health", fake_evaluate_realtime_health)
    monkeypatch.setattr(roxy_realtime_check, "ensure_ai_brief_report", fake_ai_brief_report)
    monkeypatch.setattr(roxy_realtime_check, "ensure_alert_quality_report", fake_alert_quality_report)
    monkeypatch.setattr(roxy_realtime_check, "ensure_output_maintenance_report", fake_output_maintenance_report)
    monkeypatch.setattr(roxy_realtime_check, "alert_quality_report_needs_recovery", lambda report: False)
    monkeypatch.setattr(roxy_realtime_check, "ai_brief_report_needs_recovery", lambda report: False)
    monkeypatch.setattr(
        roxy_realtime_check,
        "output_maintenance_report_needs_recovery",
        fake_output_maintenance_needs_recovery,
    )
    monkeypatch.setattr(
        "sys.argv",
        [
            "roxy_realtime_check.py",
            "--no-lock",
            "--no-history",
            "--no-fail",
            "--base-dir",
            str(tmp_path),
            "--json-path",
            str(tmp_path / "health.json"),
            "--text-path",
            str(tmp_path / "health.txt"),
            "--ensure-alert-quality-report",
            "--ensure-output-maintenance-report",
        ],
    )

    roxy_realtime_check.main()
    capsys.readouterr()

    payload = json.loads((tmp_path / "health.json").read_text())
    output_check = next(item for item in payload["checks"] if item["name"] == "output_maintenance_report")
    assert calls.count("output_maintenance") == 1
    assert calls.index("alert_quality") < calls.index("output_maintenance")
    assert calls[-1] == "health"
    assert output_check["status"] == "OK"
    assert payload["output_maintenance_autoheal"]["action"] == "trimmed"


