def test_main_refreshes_health_history_check_after_append_without_trim(tmp_path, monkeypatch, capsys):
    history_path = tmp_path / "history.jsonl"
    now = datetime.now(timezone.utc)
    history_path.write_text(
        json.dumps({"status": "OK", "generated_at": (now - timedelta(minutes=2)).isoformat()}) + "\n"
    )

    def fake_evaluate_realtime_health(**kwargs):
        return {
            "generated_at": now.isoformat(),
            "status": "OK",
            "ok": True,
            "checks": [{"name": "heartbeat", "status": "OK", "detail": "done"}],
        }

    def fake_post_append_maintenance(**kwargs):
        return {
            "action": "skipped_not_due",
            "ok": True,
            "history_path": str(kwargs["history_path"]),
            "before_size_bytes": Path(kwargs["history_path"]).stat().st_size,
            "target_bytes": int(int(kwargs["max_bytes"]) * DEFAULT_HEALTH_HISTORY_MAINTENANCE_TARGET_RATIO),
        }

    monkeypatch.setattr(roxy_realtime_check, "evaluate_realtime_health", fake_evaluate_realtime_health)
    monkeypatch.setattr(
        roxy_realtime_check,
        "ensure_post_append_health_history_maintenance",
        fake_post_append_maintenance,
    )
    monkeypatch.setattr(
        "sys.argv",
        [
            "roxy_realtime_check.py",
            "--no-lock",
            "--no-fail",
            "--json-path",
            str(tmp_path / "health.json"),
            "--text-path",
            str(tmp_path / "health.txt"),
            "--history-path",
            str(history_path),
            "--history-max-entries",
            "100",
            "--history-max-bytes",
            "1000000",
            "--history-min-entries",
            "1",
        ],
    )

    roxy_realtime_check.main()
    capsys.readouterr()

    payload = json.loads((tmp_path / "health.json").read_text())
    post_maintenance = payload["health_history_post_append_maintenance"]
    history_lines = history_path.read_text().splitlines()
    history_check = next(item for item in payload["checks"] if item["name"] == "health_history_integrity")
    latest_history = json.loads(history_lines[-1])

    assert post_maintenance["action"] == "skipped_not_due"
    assert post_maintenance["history_entry_rewritten"] is True
    assert post_maintenance["after_line_count"] == len(history_lines)
    assert history_check["line_count"] == len(history_lines)
    assert history_check["post_append_maintenance_action"] == "skipped_not_due"
    assert history_check["post_append_maintenance_after_budget_ratio"] == post_maintenance["after_budget_ratio"]
    assert "post append skipped_not_due" in history_check["detail"]
    assert latest_history["metrics"]["health_history_line_count"] == len(history_lines)
    assert latest_history["metrics"]["health_history_post_append_maintenance_action"] == "skipped_not_due"


