def test_ensure_status_snapshot_report_runs_watch_builder_and_validates_status(tmp_path, monkeypatch):
    alerts = tmp_path / "alerts"
    alerts.mkdir()
    calls = []
    fresh_generated_at = datetime.now(timezone.utc).isoformat()

    class Result:
        returncode = 0
        stdout = "Roxy AI alerts: 1 | watch: 2\n"
